import React, { useEffect, useState, useMemo } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { fetchProducts } from '../store/slices/productslice';
import ProductCard from '../components/product/productcart';
import LoadingSpinner from '../components/common/lodingspinner';
import { MOCK_PRODUCTS } from '../utils/mockproducts';
import { ChevronDown } from 'lucide-react';

const SIDEBAR_CATEGORIES = {
    'LIVING ROOM': {
        'SOFAS': ['Fabric Sofas', 'Wooden Sofas', 'L-Shaped Sofas', 'Sofa Cum Beds', 'Recliners'],
        'SEATING': ['Lounge Chairs', 'Accent Chairs', 'Wing Chairs', 'Benches', 'Pouffes'],
        'TABLES': ['Coffee Tables', 'Side Tables', 'Console Tables', 'End Tables'],
        'STORAGE': ['TV Units', 'Bookshelves', 'Display Units', 'Shoe Racks']
    },
    'BEDROOM': {
        'BEDS': ['Solid Wood Beds', 'Upholstered Beds', 'Beds with Storage', 'King Size Beds', 'Queen Size Beds'],
        'STORAGE': ['Wardrobes', 'Chest of Drawers', 'Bedside Tables', 'Dressers'],
        'MATTRESSES': ['Memory Foam', 'Orthopedic', 'Dual Comfort', 'Coir Mattresses']
    },
    'DINING': {
        'DINING SETS': ['4 Seater Dining Sets', '6 Seater Dining Sets', '8 Seater Dining Sets', 'Extendable Dining'],
        'DINING STORAGE': ['Crockery Units', 'Kitchen Cabinets', 'Sideboards'],
        'DINING DECOR': ['Table Linens', 'Coasters', 'Dining Serveware']
    },
    'STUDY': {
        'STUDY TABLES': ['Solid Wood Tables', 'Computer Tables', 'Foldable Tables'],
        'OFFICE CHAIRS': ['Ergonomic Chairs', 'Executive Chairs', 'Study Chairs'],
        'OFFICE STORAGE': ['File Cabinets', 'Office Bookcases', 'Wall Shelves']
    }
};

const AllProductsPage = () => {
    const dispatch = useDispatch();
    const navigate = useNavigate();
    const [searchParams, setSearchParams] = useSearchParams();

    const [selectedCategory, setSelectedCategory] = useState(
        searchParams.get('category') || 'all'
    );
    const [activeAccordion, setActiveAccordion] = useState(null);
    const [sortBy, setSortBy] = useState(searchParams.get('sort') || 'newest');
    const [page, setPage] = useState(parseInt(searchParams.get('page')) || 1);

    const { items: apiItems, loading, error } = useSelector(
        (state) => state.products
    );

    const items = useMemo(() => {
        return (apiItems && apiItems.length > 0) ? apiItems : MOCK_PRODUCTS;
    }, [apiItems]);

    const useMockData = useMemo(() => {
        return (!apiItems || apiItems.length === 0);
    }, [apiItems]);

    const filteredProducts = useMemo(() => {
        if (selectedCategory === 'all') return items;
        return items.filter(product => {
            const mainMatch = product.category?.toUpperCase() === selectedCategory.toUpperCase();
            const subMatch = product.subCategory?.toUpperCase() === selectedCategory.toUpperCase();
            return mainMatch || subMatch;
        });
    }, [items, selectedCategory]);

    const sortedProducts = useMemo(() => {
        return [...filteredProducts].sort((a, b) => {
            const priceA = a.variants?.[0]?.price || a.finalPrice || 0;
            const priceB = b.variants?.[0]?.price || b.finalPrice || 0;
            switch (sortBy) {
                case 'price_low': return priceA - priceB;
                case 'price_high': return priceB - priceA;
                case 'popular': return (b.rating || 0) - (a.rating || 0);
                case 'rating': return (b.rating || 0) - (a.rating || 0);
                case 'newest':
                default: return 0;
            }
        });
    }, [filteredProducts, sortBy]);

    const startIdx = (page - 1) * 20;
    const paginatedProducts = sortedProducts.slice(startIdx, startIdx + 20);
    const calculatedTotalPages = Math.ceil(sortedProducts.length / 20);

    useEffect(() => {
        const params = { page, limit: 20 };
        if (selectedCategory !== 'all') params.category = selectedCategory;
        if (sortBy !== 'newest') params.sort = sortBy;

        if (!useMockData) dispatch(fetchProducts(params));

        const newSearchParams = new URLSearchParams();
        if (selectedCategory !== 'all') newSearchParams.set('category', selectedCategory);
        if (sortBy !== 'newest') newSearchParams.set('sort', sortBy);
        if (page !== 1) newSearchParams.set('page', page);
        setSearchParams(newSearchParams);
    }, [dispatch, selectedCategory, sortBy, page, setSearchParams, useMockData]);

    const handleMainCategoryClick = (mainCat) => {
        setActiveAccordion(activeAccordion === mainCat ? null : mainCat);
        setSelectedCategory(mainCat);
        setPage(1);
    };

    const handleSubCategoryClick = (subCat) => {
        setSelectedCategory(subCat);
        setPage(1);
    };

    const handleSortChange = (e) => {
        setSortBy(e.target.value);
        setPage(1);
    };

    const getDisplayCategory = () => {
        if (selectedCategory === 'all') return 'All Products';
        return selectedCategory.split(' ').map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase()).join(' ');
    };

    if (error && !useMockData) {
        return (
            <div className="bg-gray-50 min-h-screen py-12">
                <div className="container mx-auto px-4">
                    <div className="text-center">
                        <h1 className="text-3xl font-bold text-red-600 mb-4">Error Loading Products</h1>
                        <p className="text-gray-600 mb-6">{error}</p>
                        <button onClick={() => window.location.reload()} className="bg-brand-orange text-white px-6 py-3 rounded-lg font-semibold hover:bg-orange-600 transition">
                            Try Again
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="bg-gray-50 min-h-screen">

            {/* EXACT Original Header */}
            <div className="bg-white border-b border-gray-100 py-6 md:py-8">
                <div className="container mx-auto px-4">
                    <div className="mb-4">
                        <button
                            onClick={() => navigate('/')}
                            className="text-gray-600 text-sm hover:text-brand-orange transition flex items-center gap-1 outline-none focus:outline-none focus-visible:outline-none"
                        >
                            ← Back to Home
                        </button>
                    </div>
                    <h1 className="text-3xl md:text-4xl font-bold text-gray-900 mb-2">
                        {getDisplayCategory()}
                    </h1>
                    <p className="text-gray-600">
                        Showing {paginatedProducts.length > 0 ? startIdx + 1 : 0} -{' '}
                        {startIdx + paginatedProducts.length} of {sortedProducts.length} products
                        {useMockData && <span className="text-amber-600 ml-2">(Demo Data)</span>}
                    </p>
                </div>
            </div>

            {/* EXACT Original Grid Wrapper */}
            <div className="container mx-auto px-4 py-8 md:py-12">
                <div className="grid grid-cols-12 gap-6 md:gap-8">

                    {/* LEFT SIDEBAR */}
                    <div className="col-span-12 md:col-span-3">

                        {/* Categories Box */}
                        <div className="bg-white rounded-lg shadow-sm border border-gray-100 p-6">
                            <h3 className="text-lg font-bold text-gray-900 mb-4">Categories</h3>
                            <div className="space-y-1.5">

                                {/* All Products Button */}
                                <button
                                    onClick={() => { setSelectedCategory('all'); setActiveAccordion(null); setPage(1); }}
                                    className={`w-full text-left px-4 py-2.5 rounded-lg transition-colors duration-200 font-medium text-[15px] outline-none focus:outline-none focus-visible:outline-none select-none ${selectedCategory === 'all'
                                            ? 'bg-brand-orange text-white'
                                            : 'bg-transparent text-gray-700 hover:bg-gray-50'
                                        }`}
                                >
                                    All Products
                                </button>

                                {/* Premium Accordion Categories */}
                                {Object.keys(SIDEBAR_CATEGORIES).map((mainCat) => (
                                    <div key={mainCat} className="flex flex-col">
                                        <button
                                            onClick={() => handleMainCategoryClick(mainCat)}
                                            className={`w-full flex items-center justify-between px-4 py-2.5 rounded-lg transition-colors duration-200 font-medium text-[15px] outline-none focus:outline-none focus-visible:outline-none select-none ${activeAccordion === mainCat
                                                    ? 'bg-orange-50 text-brand-orange'
                                                    : 'bg-transparent text-gray-700 hover:bg-gray-50'
                                                }`}
                                        >
                                            <span className="capitalize">{mainCat.toLowerCase()}</span>
                                            <ChevronDown
                                                size={16}
                                                className={`transition-transform duration-300 ease-out ${activeAccordion === mainCat ? 'rotate-180 text-brand-orange' : 'text-gray-400'
                                                    }`}
                                            />
                                        </button>

                                        {/* Smooth Dropdown Animation */}
                                        <div className={`grid transition-all duration-300 ease-[cubic-bezier(0.4,0,0.2,1)] ${activeAccordion === mainCat ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'
                                            }`}>
                                            <div className="overflow-hidden">
                                                <div className="pl-5 pr-2 space-y-5 py-3 border-l-2 border-gray-100 ml-5 my-2">
                                                    {Object.entries(SIDEBAR_CATEGORIES[mainCat]).map(([groupName, items]) => (
                                                        <div key={groupName}>
                                                            <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-3 select-none">{groupName}</h4>
                                                            <ul className="space-y-1">
                                                                {items.map(item => (
                                                                    <li key={item}>
                                                                        <button
                                                                            onClick={() => handleSubCategoryClick(item)}
                                                                            className="group text-sm text-left w-full py-1.5 outline-none focus:outline-none focus-visible:outline-none select-none flex items-center relative"
                                                                        >
                                                                            {/* Smooth Dot Animation (Scaling instead of shifting text) */}
                                                                            <span className={`absolute -left-4 w-1.5 h-1.5 rounded-full bg-brand-orange transition-all duration-300 ease-out ${selectedCategory === item ? 'scale-100 opacity-100' : 'scale-0 opacity-0'
                                                                                }`}></span>

                                                                            {/* Color fade instead of jumping right */}
                                                                            <span className={`transition-colors duration-200 ${selectedCategory === item
                                                                                    ? 'text-brand-orange font-semibold'
                                                                                    : 'text-gray-500 hover:text-gray-900'
                                                                                }`}>
                                                                                {item}
                                                                            </span>
                                                                        </button>
                                                                    </li>
                                                                ))}
                                                            </ul>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>

                        {/* Filters / Sort By Box */}
                        <div className="bg-white rounded-lg shadow-sm border border-gray-100 p-6 mt-6">
                            <h3 className="text-lg font-bold text-gray-900 mb-4">Sort By</h3>
                            <div className="relative">
                                <select
                                    value={sortBy}
                                    onChange={handleSortChange}
                                    className="w-full px-4 py-2.5 border border-gray-200 rounded-lg text-gray-700 text-sm focus:outline-none focus:ring-1 focus:ring-brand-orange focus:border-brand-orange transition-colors cursor-pointer bg-transparent appearance-none"
                                >
                                    <option value="newest">Newest</option>
                                    <option value="price_low">Price: Low to High</option>
                                    <option value="price_high">Price: High to Low</option>
                                    <option value="popular">Most Popular</option>
                                    <option value="rating">Top Rated</option>
                                </select>
                                <ChevronDown size={16} className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
                            </div>
                        </div>
                    </div>

                    {/* EXACT Original Main Content - Products Grid */}
                    <div className="col-span-12 md:col-span-9">
                        {loading && items.length === 0 ? (
                            <div className="flex justify-center items-center py-20">
                                <LoadingSpinner />
                            </div>
                        ) : paginatedProducts.length === 0 ? (
                            <div className="bg-white rounded-lg shadow-sm border border-gray-100 p-12 text-center">
                                <h3 className="text-xl font-bold text-gray-900 mb-2">No Products Found</h3>
                                <p className="text-gray-600 mb-6">Try adjusting your filters or browse other categories</p>
                                <button
                                    onClick={() => {
                                        setSelectedCategory('all');
                                        setActiveAccordion(null);
                                    }}
                                    className="bg-brand-orange text-white px-6 py-3 rounded-lg font-semibold hover:bg-orange-600 transition outline-none focus:outline-none"
                                >
                                    View All Products
                                </button>
                            </div>
                        ) : (
                            <>
                                {/* Products Grid */}
                                <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 md:gap-6 mb-8">
                                    {paginatedProducts.map((product) => (
                                        <ProductCard key={product.id || product._id} product={product} />
                                    ))}
                                </div>

                                {/* Pagination */}
                                {calculatedTotalPages > 1 && (
                                    <div className="flex justify-center items-center gap-2 py-8">
                                        <button
                                            onClick={() => setPage(Math.max(1, page - 1))}
                                            disabled={page === 1}
                                            className="px-4 py-2 border border-gray-200 rounded-lg text-gray-700 hover:border-brand-orange hover:text-brand-orange disabled:opacity-50 disabled:cursor-not-allowed transition outline-none focus:outline-none focus-visible:outline-none"
                                        >
                                            Previous
                                        </button>

                                        {Array.from({ length: Math.min(calculatedTotalPages, 5) }, (_, i) => {
                                            const pageNum = page > 3 ? page - 2 + i : i + 1;
                                            return pageNum <= calculatedTotalPages ? pageNum : null;
                                        }).map(
                                            (p) => p && (
                                                <button
                                                    key={p}
                                                    onClick={() => setPage(p)}
                                                    className={`px-3 py-2 rounded-lg transition-all duration-200 font-medium outline-none focus:outline-none focus-visible:outline-none ${page === p
                                                            ? 'bg-brand-orange text-white'
                                                            : 'border border-gray-200 text-gray-700 hover:border-brand-orange hover:text-brand-orange'
                                                        }`}
                                                >
                                                    {p}
                                                </button>
                                            )
                                        )}

                                        <button
                                            onClick={() => setPage(Math.min(calculatedTotalPages, page + 1))}
                                            disabled={page === calculatedTotalPages}
                                            className="px-4 py-2 border border-gray-200 rounded-lg text-gray-700 hover:border-brand-orange hover:text-brand-orange disabled:opacity-50 disabled:cursor-not-allowed transition outline-none focus:outline-none focus-visible:outline-none"
                                        >
                                            Next
                                        </button>
                                    </div>
                                )}
                            </>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default AllProductsPage;
